import java.io.*;
import java.util.*;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input to prevent XSS by escaping HTML characters
        String sanitizedInput = escapeHtml(userInput);

        String welcomeMessage = "Welcome, " + sanitizedInput + "!";

        // Display the sanitized welcome message
        System.out.println(welcomeMessage);
    }

    // Method to escape HTML special characters in user input
    private static String escapeHtml(String input) {
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
